content:
{
  "sentences": [
    {
      "text": "你現在在做什麼？",
      "pinyin": "Nǐ xiànzài zài zuò shénme?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 zuo4 shen2me0",
      "translation_en": "What are you doing now?",
      "translation_ko": "지금 뭐 하고 있어요?"
    },
    {
      "text": "我正在上網。",
      "pinyin": "Wǒ zhèngzài shàngwǎng.",
      "pinyin_numeric": "wo3 zheng4zai4 shang4wang3",
      "translation_en": "I am browsing the internet.",
      "translation_ko": "저는 인터넷을 하고 있어요."
    },
    {
      "text": "他在忙著寫功課。",
      "pinyin": "Tā zài mángzhe xiě gōngkè.",
      "pinyin_numeric": "ta1 zai4 mang2zhe0 xie3 gong1ke4",
      "translation_en": "He is busy doing homework.",
      "translation_ko": "그는 숙제를 하고 있어요."
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "我現在在忙，等一下再回你訊息。",
      "pinyin": "Wǒ xiànzài zài máng, děng yīxià zài huí nǐ xùnxí.",
      "pinyin_numeric": "wo3 xian4zai4 zai4 mang2, deng3 yi1xia4 zai4 hui2 ni3 xun4xi2",
      "translation_en": "I am busy now, I'll reply to your message later.",
      "translation_ko": "지금 바빠서, 잠시 후에 메시지 답장할게요."
    },
    {
      "text": "你現在有空嗎？",
      "pinyin": "Nǐ xiànzài yǒu kòng ma?",
      "pinyin_numeric": "ni3 xian4zai4 you3 kong4 ma0",
      "translation_en": "Are you free now?",
      "translation_ko": "지금 시간 있어요?"
    },
    {
      "text": "不好意思，我現在在忙。",
      "pinyin": "Bù hǎoyìsi, wǒ xiànzài zài máng.",
      "pinyin_numeric": "bu4 hao3yi4si0, wo3 xian4zai4 zai4 mang2",
      "translation_en": "Sorry, I am busy right now.",
      "translation_ko": "죄송합니다, 지금 바빠요."
    },
    {
      "text": "他正在開會，不方便講電話。",
      "pinyin": "Tā zhèngzài kāihuì, bù fāngbiàn jiǎng diànhuà.",
      "pinyin_numeric": "ta1 zheng4zai4 kai1hui4, bu4 fang1bian4 jiang3 dian4hua4",
      "translation_en": "He is in a meeting and not available to talk on the phone.",
      "translation_ko": "그는 회의 중이라 전화를 받기 어려워요."
    },
    {
      "text": "我還在路上，快到了。",
      "pinyin": "Wǒ hái zài lùshàng, kuài dào le.",
      "pinyin_numeric": "wo3 hai2 zai4 lu4shang4, kuai4 dao4 le0",
      "translation_en": "I am still on the way, almost there.",
      "translation_ko": "아직 가는 중인데, 곧 도착할 거예요."
    },
    {
      "text": "你現在方便嗎？我想跟你聊天。",
      "pinyin": "Nǐ xiànzài fāngbiàn ma? Wǒ xiǎng gēn nǐ liáotiān.",
      "pinyin_numeric": "ni3 xian4zai4 fang1bian4 ma0? wo3 xiang3 gen1 ni3 liao2tian1",
      "translation_en": "Are you free now? I want to chat with you.",
      "translation_ko": "지금 괜찮아요? 당신과 이야기하고 싶어요."
    }
  ]
}
